import React, { useState, useEffect } from 'react';
import { Platform, Alert } from 'react-native';
import { 
  purchaseItem,
  consumePurchase,
  getAvailablePurchases,
  finishTransaction
} from 'react-native-iap';
import { 
  GooglePay,
  ApplePay,
  Stripe,
  PayPal
} from 'react-native-payments';

const PaymentModule = () => {
  const [isInitialized, setIsInitialized] = useState(false);
  const [availableProducts, setAvailableProducts] = useState([]);
  const [userPurchases, setUserPurchases] = useState([]);

  const initializePayment = async () => {
    try {
      if (Platform.OS === 'ios') {
        await GooglePay.isAvailable();
      } else {
        await ApplePay.isAvailable();
      }
      
      const products = await getAvailablePurchases();
      setAvailableProducts(products);
      setIsInitialized(true);
    } catch (error) {
      console.error('Payment initialization failed:', error);
    }
  };

  const processPurchase = async (productId, paymentMethod) => {
    try {
      let purchase;
      
      if (paymentMethod === 'iap') {
        purchase = await purchaseItem(productId);
      } else {
        purchase = await processExternalPayment(productId, paymentMethod);
      }

      if (purchase) {
        await consumePurchase(purchase.purchaseToken);
        await finishTransaction(purchase.transactionId);
        return { success: true, purchase };
      }
    } catch (error) {
      Alert.alert('Purchase Failed', error.message);
      return { success: false, error };
    }
  };

  const processExternalPayment = async (productId, method) => {
    try {
      switch (method) {
        case 'googlepay':
          return await GooglePay.processPayment(productId);
        case 'applepay':
          return await ApplePay.processPayment(productId);
        case 'stripe':
          return await Stripe.processPayment(productId);
        case 'paypal':
          return await PayPal.processPayment(productId);
        default:
          throw new Error('Unsupported payment method');
      }
    } catch (error) {
      throw new Error(`Payment processing failed: ${error.message}`);
    }
  };

  const validatePaymentData = (data) => {
    const { amount, currency, userId } = data;
    
    if (!amount || amount <= 0) {
      throw new Error('Invalid amount');
    }
    
    if (!currency || currency.length !== 3) {
      throw new Error('Invalid currency code');
    }
    
    if (!userId) {
      throw new Error('User ID required');
    }
    
    return true;
  };

  const secureTransaction = async (transactionData) => {
    try {
      validatePaymentData(transactionData);
      
      const encryptedData = await encryptData(transactionData);
      const response = await fetch('/api/secure-transaction', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${await getAuthToken()}`
        },
        body: JSON.stringify(encryptedData)
      });
      
      const result = await response.json();
      
      if (result.success) {
        await updateLocalPurchases(transactionData);
        return result;
      } else {
        throw new Error(result.error || 'Transaction failed');
      }
    } catch (error) {
      console.error('Secure transaction failed:', error);
      throw error;
    }
  };

  const encryptData = async (data) => {
    const crypto = require('react-native-crypto');
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipher('aes-256-cbc', process.env.ENCRYPTION_KEY);
    let encrypted = cipher.update(JSON.stringify(data), 'utf8', 'hex');
    encrypted += cipher.final('hex');
    return { encrypted, iv: iv.toString('hex') };
  };

  const getAuthToken = async () => {
    const token = await AsyncStorage.getItem('auth_token');
    return token;
  };

  const updateLocalPurchases = async (purchaseData) => {
    const purchases = await AsyncStorage.getItem('user_purchases');
    const purchaseList = purchases ? JSON.parse(purchases) : [];
    purchaseList.push(purchaseData);
    await AsyncStorage.setItem('user_purchases', JSON.stringify(purchaseList));
  };

  useEffect(() => {
    initializePayment();
    return () => {
      // Cleanup
    };
  }, []);

  return {
    isInitialized,
    availableProducts,
    processPurchase,
    secureTransaction,
    validatePaymentData
  };
};

export default PaymentModule;